\u540C\u4E00\u4E2A\u4EBA\u5728\u4E00\u4E2A\u9886\u57DF\u53EF\u4EE5\u6781\u5176\u7406\u6027\uFF0C\u5728\u53E6\u4E00\u4E2A\u9886\u57DF\u53EF\u4EE5\u6781\u5176\u611A\u8822\u3002\u5BF9\u5B97\u6559\u6000\u7591\u7684\u4EBA\u53EF\u80FD\u5728\u80A1\u5E02\u91CC\u5F53\u97ED\u83DC\u3002\u4EA4\u6613\u5929\u624D\u53EF\u80FD\u4E0D\u61C2\u5982\u4F55\u7BA1\u7406\u5A5A\u59FB\u3002

